import React, { useEffect, useMemo, useRef, useState } from 'react';
import { createRoot } from 'react-dom/client';
import './styles.css';

type Status = { stage: string; current: number; total: number; message: string; stage_index?:number; stage_count?:number; stage_name?:string; stage_percent?:number; overall_percent?:number; percent?:number };
type Manifest = { year?:number; doy?:number; station_count:number; stations?:string[]; gps_prns:string[]; time_range_hours:{min:number|null;max:number|null}; total_rows_seen:number; valid_rows_after_filters:number; malformed_row_count:number; non_gps_row_count:number; low_elevation_row_count:number; out_of_bounds_row_count:number; applied_filters:Record<string,string|number>; };
type Point = { station:string; time_h:number; prn:string; dtec:number; azimuth:number; elevation:number; ipp_lon:number; ipp_lat:number };
type StationMarker = { station:string; lon:number; lat:number; height?:number; full_site_id?:string; city?:string; country?:string; domes?:string; approximate?:boolean; source?:string };
type StationCatalog = { total:number; resolved:number; unresolved:number; stations:StationMarker[] };
type MapLayers = { borders:boolean; grid:boolean; rays:boolean; ipp:boolean; stations:boolean; stationLabels:boolean; dtec:boolean; solar:boolean; solarHorizon:boolean; solarCivil:boolean; solarNautical:boolean; solarAstronomical:boolean; solarIono:boolean; solarShade:boolean };
const DEFAULT_TWILIGHT_OPACITY = 35;
function loadTwilightOpacity() { const raw = Number(window.localStorage.getItem('tid.map.twilightOpacity')); return Number.isFinite(raw) ? Math.max(0, Math.min(100, raw)) : DEFAULT_TWILIGHT_OPACITY; }
type MapDisplaySettings = { ippMarkerSize:number; stationMarkerSize:number; stationLabelSize:number; rayWidth:number; rayOpacity:number; dtecRange:number };
const DEFAULT_MAP_DISPLAY: MapDisplaySettings = { ippMarkerSize:4, stationMarkerSize:7, stationLabelSize:10, rayWidth:0.8, rayOpacity:30, dtecRange:1 };
function loadMapDisplaySettings():MapDisplaySettings { try { return {...DEFAULT_MAP_DISPLAY, ...JSON.parse(window.localStorage.getItem('tid.map.display') || '{}')}; } catch { return DEFAULT_MAP_DISPLAY; } }
type SolarGeometry = { utc_datetime:string; subsolar_latitude:number; subsolar_longitude:number; lon_values:number[]; lat_values:number[]; solar_elevation_deg:number[][]; contour_thresholds_deg:number[]; ionospheric_shadow:{earth_radius_km:number; shell_height_km:number; formula:string; threshold_deg:number} };
type InterpolationSummary = { grid_step_deg?:number; grid_lat_count?:number; grid_lon_count?:number; minimum_epoch_ipp_count?:number; eligible_arc_count:number; ineligible_arc_count:number; planned_map_count:number; ready_map_count:number; missing_map_count:number; failed_map_count:number; arcs?:{prn:string; arc_index:number; expected:number; ready:number; failed:number; status:string}[] };
type InterpolationProgress = { grid_step_deg?:number; grid_lat_count?:number; grid_lon_count?:number; state:string; current:number; total:number; current_prn?:string|null; current_arc_index?:number|null; current_epoch_index?:number|null; generated:number; already_ready:number; skipped:number; skipped_low_station_coverage?:number; failed:number; message:string; started_at_utc?:string|null; elapsed_seconds?:number|null; completed_element_count?:number; mean_seconds_per_element?:number|null; remaining_seconds?:number|null; estimated_finish_utc?:string|null };
type RasterGrid = { grid_step_deg?:number; prn:string; requested_time_h:number; actual_time_h:number; epoch_index:number; lon_values:number[]; lat_values:number[]; values:number[][]; valid_mask:boolean[][]; method:string; projection:string; point_count:number; station_count:number; status:string; message?:string; image_href?:string };
type Arc = { raw_epoch_count?:number; planned_interpolation_count?:number; low_point_epoch_count?:number; ready_map_count?:number; minimum_epoch_ipp_count?:number; prn:string; arc_index:number; total_epoch_count?:number; usable_epoch_count?:number; low_coverage_epoch_count?:number; first_usable_time_h?:number|null; last_usable_time_h?:number|null; no_usable_epoch_reason?:string|null; start_time_h:number; end_time_h:number; duration_min:number; row_count:number; station_count:number; epoch_count:number; max_station_count:number; median_station_count:number; eligible_for_interpolation:boolean; ineligibility_reasons:string[]; interpolation_status:string; generated_map_count:number; failed_map_count:number };
type Series = { station:string; prn:string; time_start_h?:number|null; time_end_h?:number|null; points:{time_h:number; dtec:number; elevation:number; ipp_lon:number; ipp_lat:number}[] };
type FftResult = { station:string; prn:string; period_min:number[]; amplitude:number[] };
type MorletResult = { station:string; prn:string; time_h:number[]; period_min:number[]; power:number[][] };
type PanelId = 'summary'|'visibility'|'map'|'timeseries'|'spectral'|'candidates'|'report';
type MapMode = 'epoch'|'satellite'|'window';
type OperationKey = 'visibility'|'preview'|'timeseries'|'spectral'|'import'|'browse';
type Operation = { key: OperationKey; label: string; slow: boolean } | null;
const API = 'http://127.0.0.1:8000';
type Viewport = { lon_min:number; lon_max:number; lat_min:number; lat_max:number };
const EUROPE_VIEWPORT: Viewport = { lon_min: -20, lon_max: 50, lat_min: 20, lat_max: 80 };
const NAV_LIMITS: Viewport = { lon_min: -180, lon_max: 180, lat_min: -85, lat_max: 85 };
const bounds = { lonMin: -20, lonMax: 50, latMin: 20, latMax: 80 }; // import/filter domain; do not use for map viewport
const panels:{id:PanelId; n:number; title:string}[] = [
  {id:'summary', n:1, title:'Data import & summary'}, {id:'visibility', n:2, title:'Satellite visibility'}, {id:'map', n:3, title:'Map explorer'}, {id:'timeseries', n:4, title:'Station time series'}, {id:'spectral', n:5, title:'Spectral analysis'}, {id:'candidates', n:6, title:'TID candidates'}, {id:'report', n:7, title:'Event report'},
];

function App() {
  const [folderPath, setFolderPath] = useState('');
  const [minElevationDeg, setMinElevationDeg] = useState(50);
  const [status, setStatus] = useState<Status>({ stage: 'idle', current: 0, total: 0, message: 'Idle' });
  const [manifest, setManifest] = useState<Manifest | null>(null);
  const [points, setPoints] = useState<Point[]>([]);
  const [stationMarkers, setStationMarkers] = useState<StationMarker[]>([]);
  const [stationCatalog, setStationCatalog] = useState<StationCatalog | null>(null);
  const [rasterAvailable, setRasterAvailable] = useState(false);
  const [activeRaster, setActiveRaster] = useState<RasterGrid | null>(null);
  const [rasterStatus, setRasterStatus] = useState('No interpolated grid loaded.');
  const [rasterOpacity, setRasterOpacity] = useState(70);
  const [twilightOpacity, setTwilightOpacity] = useState(loadTwilightOpacity);
  const [mapDisplay, setMapDisplay] = useState<MapDisplaySettings>(loadMapDisplaySettings);
  const [interpolationSummary, setInterpolationSummary] = useState<InterpolationSummary | null>(null);
  const [interpolationProgress, setInterpolationProgress] = useState<InterpolationProgress>({state:'idle', current:0, total:0, generated:0, already_ready:0, skipped:0, failed:0, message:'Idle'});
  const [interpolationSlow, setInterpolationSlow] = useState(false);
  const [minimumEpochIppCount, setMinimumEpochIppCount] = useState(30);
  const [interpolationGridStep, setInterpolationGridStep] = useState(1.0);
  const [, setEtaTick] = useState(0);
  const epochRequestSeq = useRef(0);
  const solarRequestSeq = useRef(0);
  const [layers, setLayers] = useState<MapLayers>({borders:true, grid:true, rays:false, ipp:true, stations:true, stationLabels:false, dtec:false, solar:true, solarHorizon:true, solarCivil:false, solarNautical:false, solarAstronomical:false, solarIono:true, solarShade:true});
  const [solarGeometry, setSolarGeometry] = useState<SolarGeometry | null>(null);
  const [viewport, setViewport] = useState<Viewport>(EUROPE_VIEWPORT);
  const [limitReached, setLimitReached] = useState(false);
  const [previewMeta, setPreviewMeta] = useState('');
  const [prn, setPrn] = useState('');
  const [timeH, setTimeH] = useState('0');
  const [startTimeH, setStartTimeH] = useState('');
  const [endTimeH, setEndTimeH] = useState('');
  const [tol, setTol] = useState(15);
  const [maxPoints, setMaxPoints] = useState(5000);
  const [mapMode, setMapMode] = useState<MapMode>('epoch');
  const [arcs, setArcs] = useState<Arc[]>([]);
  const [world, setWorld] = useState<any>(null);
  const [worldStatus, setWorldStatus] = useState('Waiting for backend…');
  const [worldError, setWorldError] = useState('');
  const [open, setOpen] = useState<Record<PanelId, boolean>>({summary:true, visibility:true, map:true, timeseries:true, spectral:false, candidates:false, report:false});
  const [selected, setSelected] = useState<string[]>([]);
  const [series, setSeries] = useState<Series[]>([]);
  const [selectedLine, setSelectedLine] = useState('');
  const [operation, setOperation] = useState<Operation>(null);
  const [requestedTimeH, setRequestedTimeH] = useState<string>('');
  const [actualTimeH, setActualTimeH] = useState<string>('');
  const [stationCount, setStationCount] = useState(0);
  const [mapError, setMapError] = useState('');
  const [mapEnlarged, setMapEnlarged] = useState(false);
  const [timeSeriesEnlarged, setTimeSeriesEnlarged] = useState(false);
  const [spectralEnlarged, setSpectralEnlarged] = useState(false);
  const [visibilityEnlarged, setVisibilityEnlarged] = useState(false);
  const [selectedArcKey, setSelectedArcKey] = useState('');
  const [sidebarHidden, setSidebarHidden] = useState(() => window.localStorage.getItem('tid.sidebar.hidden') === 'true');
  const [fft, setFft] = useState<FftResult | null>(null);
  const [morlet, setMorlet] = useState<MorletResult | null>(null);
  const [spectralStatus, setSpectralStatus] = useState('');
  const progress = useMemo(() => Math.round(status.overall_percent ?? (status.total > 0 ? (status.current / status.total) * 100 : 0)), [status]);
  const stageProgress = useMemo(() => Math.round(status.stage_percent ?? (status.total > 0 ? (status.current / status.total) * 100 : 0)), [status]);
  const interpolationRunning = interpolationProgress.state === 'running' || interpolationProgress.state === 'cancelling';
  const topStatusText = operation?.key === 'import' || interpolationRunning ? undefined : (worldError || worldStatus || status.message);
  const toggleSidebar = () => setSidebarHidden(hidden => !hidden);
  useEffect(() => { window.localStorage.setItem('tid.sidebar.hidden', String(sidebarHidden)); }, [sidebarHidden]);
  useEffect(() => { window.localStorage.setItem('tid.map.display', JSON.stringify(mapDisplay)); }, [mapDisplay]);
  useEffect(() => { window.localStorage.setItem('tid.map.twilightOpacity', String(twilightOpacity)); }, [twilightOpacity]);
  useEffect(() => { setActiveRaster(r => r && r.values ? {...r, image_href: rasterToImage(r, mapDisplay.dtecRange)} : r); }, [mapDisplay.dtecRange]);
  useEffect(() => { if (manifest) { loadVisibility(); refreshInterpolationSummary(); } }, [minimumEpochIppCount, interpolationGridStep]);
  useEffect(() => {
    const onKeyDown = (event:KeyboardEvent) => {
      if (event.ctrlKey && event.shiftKey && event.key.toLowerCase() === 'b') { event.preventDefault(); toggleSidebar(); }
    };
    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, []);
  const importStageText = interpolationRunning ? `Interpolating maps ${interpolationProgress.current} / ${interpolationProgress.total}` : operation?.key === 'import' ? `${status.stage_index || ''}${status.stage_count ? `/${status.stage_count}` : ''} ${status.stage_name || status.message}${status.total ? ` · ${status.current} / ${status.total}` : ''}` : (operation ? operation.label : (topStatusText || status.message));

  async function fetchWithRetry(url:string, attempts=6) {
    let lastError = new Error('Request failed');
    for (let i=0; i<attempts; i++) {
      try { const r = await fetch(url); if (r.ok || r.status < 500) return r; lastError = new Error(`${url} returned ${r.status}`); }
      catch (err:any) { lastError = err; }
      await new Promise(resolve => window.setTimeout(resolve, Math.min(2000, 250 * 2 ** i)));
    }
    throw lastError;
  }
  async function loadWorldBorders() {
    setWorldError(''); setWorldStatus('Waiting for backend…');
    try {
      await fetchWithRetry(`${API}/api/health`, 8);
      setWorldStatus('Loading world borders…');
      const r = await fetchWithRetry(`${API}/api/assets/world-borders`, 6);
      if (!r.ok) throw new Error(`World borders failed to load (${r.status})`);
      setWorld(await r.json()); setWorldStatus('Ready');
    } catch (err:any) {
      setWorld(null); setWorldStatus('Ready'); setWorldError(err?.message || 'World borders failed to load.');
    }
  }
  useEffect(() => { loadWorldBorders(); }, []);
  function applyImportStatus(update:Status) {
    setStatus(update);
    if (update.stage === 'stations_resolved') fetchStationCatalog();
    if (update.stage === 'done') { fetch(`${API}/api/manifest`).then((r) => r.ok ? r.json() : null).then((j) => { if (j) setManifest(j); }); fetchStationCatalog(); setOperation(o => o?.key === 'import' ? null : o); }
    if (update.stage === 'error' || update.stage === 'cancelled') { setOperation(o => o?.key === 'import' ? null : o); }
  }
  useEffect(() => {
    let closed = false; let ws:WebSocket|null = null; let reconnect:number|undefined;
    const connect = () => { if (closed || ws) return; ws = new WebSocket('ws://127.0.0.1:8000/ws/import-progress');
      ws.onmessage = (event) => applyImportStatus(JSON.parse(event.data) as Status);
      const retry = () => { ws = null; if (!closed) reconnect = window.setTimeout(connect, 500); };
      ws.onerror = retry; ws.onclose = retry;
    };
    connect();
    return () => { closed = true; if (reconnect) window.clearTimeout(reconnect); ws?.close(); };
  }, []);


  useEffect(() => {
    if (!interpolationRunning) return;
    const t = window.setInterval(() => setEtaTick(x => x + 1), 1000);
    return () => window.clearInterval(t);
  }, [interpolationRunning]);

  useEffect(() => {
    const ws = new WebSocket('ws://127.0.0.1:8000/ws/interpolation-progress');
    ws.onmessage = (event) => { const update = JSON.parse(event.data) as InterpolationProgress; setInterpolationProgress(update); refreshInterpolationSummary(); if (update.state === 'running') { const t = window.setTimeout(()=>setInterpolationSlow(true), 2000); return () => window.clearTimeout(t); } else { setInterpolationSlow(false); } };
    return () => ws.close();
  }, []);

  async function refreshInterpolationSummary() { if (!manifest) { setInterpolationSummary({eligible_arc_count:0,ineligible_arc_count:0,planned_map_count:0,ready_map_count:0,missing_map_count:0,failed_map_count:0}); return; } const r = await fetch(`${API}/api/interpolation/summary?${new URLSearchParams({minimum_epoch_ipp_count:String(minimumEpochIppCount), grid_step_deg:String(interpolationGridStep)})}`); if (r.ok) setInterpolationSummary(await r.json()); }
  async function startInterpolation(force=false) { const planned = interpolationSummary?.missing_map_count ?? interpolationSummary?.planned_map_count ?? 0; if (!force && !window.confirm(`This operation will generate ${planned} interpolated maps and may take a long time. Existing completed maps will be reused. Do you wish to continue?`)) return; if (force && !window.confirm('Rebuild all interpolated maps? Existing cached grids may be replaced.')) return; const body={retry_failed:force, force_rebuild:force, minimum_epoch_ipp_count:minimumEpochIppCount, grid_step_deg:interpolationGridStep}; const r=await fetch(`${API}/api/interpolation/build-all`, {method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify(body)}); if(!r.ok) throw new Error(await r.text()); setInterpolationProgress(p=>({...p,state:'running',message:'Starting interpolation build'})); await refreshInterpolationSummary(); }
  async function startArcInterpolation() { const a = arcs.find((x:Arc)=>`${x.prn}-${x.arc_index}`===selectedArcKey); if(!a) return; const body={prn:a.prn, arc_index:a.arc_index, retry_failed:false, force_rebuild:false, minimum_epoch_ipp_count:minimumEpochIppCount, grid_step_deg:interpolationGridStep}; const r=await fetch(`${API}/api/interpolation/build-arc`, {method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify(body)}); if(!r.ok) throw new Error(await r.text()); setInterpolationProgress(p=>({...p,state:'running',message:'Starting arc interpolation build'})); await refreshInterpolationSummary(); }
  async function cancelInterpolation() { const r=await fetch(`${API}/api/interpolation/cancel`, {method:'POST'}); if(!r.ok) throw new Error(await r.text()); setInterpolationProgress(p=>({...p,state:'cancelled',message:'Interpolation cancellation requested'})); await refreshInterpolationSummary(); }

  async function runOperation(key:OperationKey, label:string, work:()=>Promise<void>, clearOnDone=true) {
    setOperation({key, label, slow:false}); setStatus({stage:key, current:0, total:0, message:label});
    const timer = window.setTimeout(() => setOperation(o => o?.key === key ? {...o, slow:true} : o), 2000);
    try { await work(); } catch (err:any) { setStatus({stage:'error', current:0, total:0, message:err?.message || `${label} failed`}); throw err; }
    finally { window.clearTimeout(timer); if (clearOnDone) setOperation(o => o?.key === key ? null : o); }
  }
  async function browse() { await runOperation('browse', 'Opening folder browser…', async () => { const r = await fetch(`${API}/api/select-folder`, { method:'POST' }); const j = await r.json(); if (r.ok && j.folder_path) { setFolderPath(j.folder_path); setStatus({stage:'done', current:1, total:1, message:'Folder selected.'}); } else throw new Error(j.detail || 'Folder dialog failed'); }); }
  async function fetchStationCatalog() { const r = await fetch(`${API}/api/stations/catalog`); if (!r.ok) return; const j = await r.json(); const resolved = (j.stations || []).filter((s:any)=>s.resolved && s.lon != null && s.lat != null).map((s:any)=>({station:s.station, lon:s.lon, lat:s.lat, height:s.height, full_site_id:s.full_site_id, city:s.city, country:s.country, domes:s.domes, approximate:false, source:s.source})); setStationCatalog(j); setStationMarkers(resolved); setStationCount(j.resolved || resolved.length); }
  async function startImport() { await runOperation('import', 'Starting import…', async () => { setManifest(null); setPoints([]); setStationMarkers([]); setStationCatalog(null); setRasterAvailable(false); setActiveRaster(null); setArcs([]); setRequestedTimeH(''); setActualTimeH(''); setStationCount(0); setSolarGeometry(null); const response = await fetch(`${API}/api/import?force_rebuild=true`, { method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify({ folder_path: folderPath, min_elevation_deg: minElevationDeg }) }); if (!response.ok) throw new Error(await response.text()); startImportPolling(); }, false); }

  function startImportPolling() {
    const poll = window.setInterval(async () => {
      try {
        const r = await fetch(`${API}/api/import/status`); if (!r.ok) return;
        const update = await r.json() as Status; applyImportStatus(update);
        if (['done','error','cancelled'].includes(update.stage)) window.clearInterval(poll);
      } catch { /* polling fallback retries until terminal status */ }
    }, 500);
  }
  async function cancelImport() { const response = await fetch(`${API}/api/import/cancel`, { method:'POST' }); if (!response.ok) throw new Error(await response.text()); setStatus(s=>({...s, message:'Cancelling import after current file…'})); }
  async function loadVisibility() { await runOperation('visibility', 'Loading satellite visibility…', async () => { const r = await fetch(`${API}/api/satellites/visibility?${new URLSearchParams({minimum_epoch_ipp_count:String(minimumEpochIppCount), grid_step_deg:String(interpolationGridStep)})}`); if (!r.ok) throw new Error(await r.text()); const j = await r.json(); const next = j.arcs || []; setArcs(next); await refreshInterpolationSummary(); setStatus({stage:'done', current:1, total:1, message:`Loaded ${next.length} visibility arcs.`}); }); }
  async function loadPreview(overrideTimeH?:string|number, overridePrn?:string, forceEpoch=false) { await runOperation('preview', 'Loading map points…', async () => { setMapError(''); const safeTime = (typeof overrideTimeH === 'string' || typeof overrideTimeH === 'number') ? String(overrideTimeH) : undefined; const safePrn = typeof overridePrn === 'string' ? overridePrn : undefined; const requestedTime = safeTime ?? timeH; const requestedPrn = safePrn ?? prn; const requestedMode = forceEpoch ? 'epoch' : mapMode; const seq = requestedMode === 'epoch' ? ++epochRequestSeq.current : epochRequestSeq.current; setRequestedTimeH(requestedMode === 'epoch' ? requestedTime : ''); if (requestedMode === 'epoch' && requestedPrn && requestedTime !== '') { const q = new URLSearchParams({ prn: requestedPrn, time_h: requestedTime }); const r = await fetch(`${API}/api/map/epoch?${q}`); if (!r.ok) throw new Error(await r.text()); const j = await r.json(); if (requestedMode === 'epoch' && seq !== epochRequestSeq.current) return; const visible = (j.points || []).filter(inBounds); setPoints(visible); setStationMarkers(j.station_markers || []); setRasterAvailable(Boolean(j.raster_available)); setLimitReached(false); setActualTimeH(j.actual_time_h != null ? String(Number(j.actual_time_h).toFixed(5)) : ''); setStationCount((j.stations || []).length || new Set(visible.map((p:Point)=>p.station)).size); if (j.actual_time_h != null) setTimeH(String(Number(j.actual_time_h).toFixed(5))); if (j.actual_time_h != null) { await loadSolarGeometry(j.actual_time_h, seq); await loadEpochRaster(requestedPrn, requestedTime, seq); if (visible.length < minimumEpochIppCount) { setRasterAvailable(false); setLayers(x=>({...x,dtec:false})); setRasterStatus(`Raw epoch available: ${visible.length} IPPs. Interpolation requires at least ${minimumEpochIppCount} IPPs.`); } } const msg = `Requested ${Number(requestedTime).toFixed(5)} h; actual ${j.actual_time_h != null ? Number(j.actual_time_h).toFixed(5) : 'n/a'} h; ${visible.length} IPP points; ${((j.stations || []).length || new Set(visible.map((p:Point)=>p.station)).size)} stations`; setPreviewMeta(msg); setStatus({stage:'done', current:1, total:1, message:msg}); return; } const q = new URLSearchParams({ tolerance_seconds:String(tol), max_points:String(maxPoints) }); if (requestedPrn) q.set('prn', requestedPrn); if (requestedMode === 'epoch' && requestedTime !== '') q.set('time_h', requestedTime); if (requestedMode === 'window') { if (startTimeH !== '') q.set('start_time_h', startTimeH); if (endTimeH !== '') q.set('end_time_h', endTimeH); } const r = await fetch(`${API}/api/preview/points?${q}`); if (!r.ok) throw new Error(await r.text()); const j = await r.json(); if (requestedMode === 'epoch' && seq !== epochRequestSeq.current) return; const visible = (j.points || []).filter(inBounds); setPoints(visible); setStationMarkers(j.station_markers || []); setRasterAvailable(Boolean(j.raster_available)); setLimitReached(Boolean(j.limit_reached)); if (requestedMode === 'epoch') { const solarTime = j.actual_time_h ?? requestedTime; await loadSolarGeometry(solarTime, seq); await loadEpochRaster(requestedPrn, requestedTime, seq); } const actual = j.actual_time_h ?? j.requested_time_h ?? (requestedMode === 'epoch' ? requestedTime : 'n/a'); setActualTimeH(j.actual_time_h != null ? String(Number(j.actual_time_h).toFixed(5)) : ''); setStationCount(new Set(visible.map((p:Point)=>p.station)).size); if (requestedMode === 'epoch' && j.actual_time_h != null) setTimeH(String(Number(j.actual_time_h).toFixed(5))); const msg = `Requested ${requestedMode === 'epoch' ? requestedTime : 'n/a'} h; actual ${actual}; ${visible.length}/${j.total_matching_before_limit} IPP points; ${new Set(visible.map((p:Point)=>p.station)).size} stations`; setPreviewMeta(msg); setStatus({stage:'done', current:1, total:1, message:msg}); }); }

  async function loadSolarGeometry(time:string|number, epochSeq=epochRequestSeq.current) { if (!manifest) return; const seq = ++solarRequestSeq.current; const r = await fetch(`${API}/api/solar-geometry?${new URLSearchParams({actual_time_h:String(time)})}`); if (seq !== solarRequestSeq.current || epochSeq !== epochRequestSeq.current) return; if (r.ok) setSolarGeometry(await r.json()); }

  async function loadEpochRaster(usePrn:string, useTime:string|number, seq:number) {
    if (!usePrn || useTime === '') { if (seq === epochRequestSeq.current) { setActiveRaster(null); setRasterAvailable(false); setRasterStatus('No interpolated grid exists for this epoch.'); } return; }
    const q = new URLSearchParams({prn: usePrn, time_h: String(useTime), grid_step_deg:String(interpolationGridStep)});
    const r = await fetch(`${API}/api/interpolation/epoch?${q}`);
    if (seq !== epochRequestSeq.current) return;
    if (r.status === 404) { setActiveRaster(null); setRasterAvailable(false); setLayers(x=>({...x,dtec:false})); setRasterStatus('No interpolated grid exists for this epoch.'); return; }
    if (!r.ok) { setActiveRaster(null); setRasterAvailable(false); setRasterStatus('No interpolated grid exists for this epoch.'); return; }
    const j = await r.json() as RasterGrid;
    if (seq !== epochRequestSeq.current) return;
    if (j.status !== 'ready') { setActiveRaster(null); setRasterAvailable(false); setLayers(x=>({...x,dtec:false})); setRasterStatus(`Interpolation failed for this epoch: ${j.message || j.status}`); return; }
    const raster = {...j, image_href: rasterToImage(j, mapDisplay.dtecRange)};
    setActiveRaster(raster); setViewport(rasterViewport(raster)); setRasterAvailable(true); setRasterStatus(`Natural-neighbour grid ready: ${j.prn}, ${Number(j.actual_time_h).toFixed(5)} h, ${j.station_count} stations, ${j.grid_step_deg ?? interpolationGridStep}° grid`); setLayers(x=>({...x,dtec:true}));
  }

  function chooseArc(a:Arc) { setSelectedArcKey(`${a.prn}-${a.arc_index}`); if (!a.first_usable_time_h && a.usable_epoch_count === 0) setMapError(a.no_usable_epoch_reason || 'No usable epoch exists; showing first raw epoch.'); const firstEpoch = String(a.start_time_h.toFixed(5)); setPrn(a.prn); setTimeH(firstEpoch); setStartTimeH(String(a.start_time_h)); setEndTimeH(String(a.end_time_h)); setMapMode('epoch'); setOpen(o=>({...o,map:true})); setTimeout(() => loadPreview(firstEpoch, a.prn, true), 0); }
  function step(minutes:number) { setTimeH(v => { const next = String(Math.max(0, (Number(v || 0) + minutes / 60)).toFixed(5)); if (prn && mapMode === 'epoch') setTimeout(() => loadPreview(next), 0); return next; }); }
  function inBounds(p:Point) { return p.ipp_lon >= bounds.lonMin && p.ipp_lon <= bounds.lonMax && p.ipp_lat >= bounds.latMin && p.ipp_lat <= bounds.latMax; }
  function toggleStationId(station:string, usePrn?:string) { const id = `${station}|${usePrn || prn}`; if (!id.endsWith('|')) setSelected(s => s.includes(id) ? s.filter(x=>x!==id) : [...s, id]); }
  function toggleStation(p:Point) { if (!inBounds(p)) return; const id = `${p.station}|${p.prn}`; setSelected(s => s.includes(id) ? s.filter(x=>x!==id) : [...s, id]); }
  async function loadSeries() { await runOperation('timeseries', 'Loading time series…', async () => { const stations = selected.map(s=>s.split('|')[0]); const usePrn = prn || selected[0]?.split('|')[1]; if (!usePrn || !stations.length) return; const q = new URLSearchParams({ prn: usePrn, arc_mode:'continuous_arc' }); stations.forEach(s=>q.append('station', s)); if (startTimeH) q.set('start_time_h', startTimeH); if (endTimeH) q.set('end_time_h', endTimeH); const r = await fetch(`${API}/api/stations/timeseries?${q}`); if (!r.ok) throw new Error(await r.text()); const j = await r.json(); const next = j.series || []; setSeries(next); setStatus({stage:'done', current:1, total:1, message:`Loaded ${next.length} time series.`}); }); }
  async function computeSpectral(kind:'fft'|'morlet') { if (!selectedLine) return; const [station, usePrn] = selectedLine.split('|'); await runOperation('spectral', `Computing ${kind.toUpperCase()}…`, async () => { setSpectralStatus(`Computing ${kind.toUpperCase()}…`); const body:any = {station, prn: usePrn}; if (startTimeH) body.start_time_h = Number(startTimeH); if (endTimeH) body.end_time_h = Number(endTimeH); const r = await fetch(`${API}/api/spectral/${kind}`, {method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify(body)}); if (!r.ok) throw new Error(await r.text()); const j = await r.json(); if (kind === 'fft') setFft(j); else setMorlet(j); setSpectralStatus(`${kind.toUpperCase()} ready.`); setStatus({stage:'done', current:1, total:1, message:`${kind.toUpperCase()} ready.`}); }); }

  return <div className="app">
    <header className="topbar"><span className="brand">TID Analyzer</span><input className="folderInput" value={folderPath} onChange={e=>setFolderPath(e.target.value)} placeholder="Local daily folder path" /><span className="browseSlot"><button onClick={browse} disabled={operation?.key==='browse'} title="Choose a local daily data folder.">Browse…</button></span><label className="compactInput" title="Only observations at or above this elevation are stored in the daily working database.">Min elevation [deg]<input type="number" min="0" max="90" step="1" value={minElevationDeg} onChange={e=>setMinElevationDeg(Math.max(0, Math.min(90, Number(e.target.value))))}/></label><span className="importSlot">{operation?.key==='import' ? <button onClick={cancelImport} title="Stop import after the current file or batch.">Cancel</button> : <button onClick={startImport} disabled={Boolean(operation)} title="Import and filter the selected folder.">Import</button>}</span><div className="progressStack"><progress {...(operation && status.total === 0 ? {} : {value: progress})} max="100" />{operation?.key==='import' && <progress className="stageProgress" value={stageProgress} max="100" />}</div><span className="statusText" title={importStageText}>{importStageText}</span><span className="spinnerSlot">{(operation || interpolationRunning) && <span className="spinner" aria-label="Loading"/>}</span>{(operation?.slow || interpolationSlow) && <span className="mini">Natural-neighbour grids are being generated and stored in the daily cache. This first pass may take time.</span>}{manifest && <span className="mini">Stations {manifest.station_count} · PRNs {manifest.gps_prns.length} · Valid {manifest.valid_rows_after_filters}</span>}</header>
    <main className={`workspace ${sidebarHidden ? 'sidebarCollapsed' : ''}`}><section className="canvas"><div className="canvasHead"><h1>Map Explorer</h1><span>{previewMeta}{limitReached ? ' · sampled limit reached' : ''}</span></div><PreviewPlot raster={activeRaster} rasterOpacity={rasterOpacity} points={points} stationMarkers={stationMarkers} world={world} solarGeometry={solarGeometry} twilightOpacity={twilightOpacity} layers={layers} selected={selected} onStationClick={toggleStationId} prn={prn} actualTimeH={actualTimeH} viewport={viewport} setViewport={setViewport} display={mapDisplay}/>{worldError && <p className="warn">{worldError} <button onClick={loadWorldBorders}>Retry world borders</button></p>}{mapError && <p className="warn">{mapError}</p>}</section><button className="sidebarToggle" onClick={toggleSidebar} title="Toggle workflow panel (Ctrl+Shift+B)" aria-expanded={!sidebarHidden} aria-controls="workflow-sidebar">{sidebarHidden ? 'Show workflow panel' : 'Hide workflow panel'}</button><aside id="workflow-sidebar" className="side" aria-hidden={sidebarHidden}> {panels.map(p=><WorkflowPanel key={p.id} panel={p} open={open[p.id]} toggle={()=>setOpen(o=>({...o,[p.id]:!o[p.id]}))} onEnlarge={()=> p.id==='visibility' ? setVisibilityEnlarged(true) : p.id==='map' ? setMapEnlarged(true) : p.id==='timeseries' ? setTimeSeriesEnlarged(true) : p.id==='spectral' ? setSpectralEnlarged(true) : undefined}>{p.id==='summary' && <Summary manifest={manifest}/>} {p.id==='visibility' && <Visibility arcs={arcs} load={loadVisibility} choose={chooseArc} loading={operation?.key==='visibility'} summary={interpolationSummary} progress={interpolationProgress} minimumEpochIppCount={minimumEpochIppCount} setMinimumEpochIppCount={setMinimumEpochIppCount} startInterpolation={startInterpolation} startArcInterpolation={startArcInterpolation} cancelInterpolation={cancelInterpolation} selectedArcKey={selectedArcKey} interpolationGridStep={interpolationGridStep} setInterpolationGridStep={setInterpolationGridStep}/>} {p.id==='map' && <Explorer stationCatalog={stationCatalog} manifest={manifest} prn={prn} setPrn={setPrn} timeH={timeH} setTimeH={setTimeH} startTimeH={startTimeH} setStartTimeH={setStartTimeH} endTimeH={endTimeH} setEndTimeH={setEndTimeH} tol={tol} setTol={setTol} maxPoints={maxPoints} setMaxPoints={setMaxPoints} loadPreview={loadPreview} count={points.length} limitReached={limitReached} mapMode={mapMode} setMapMode={setMapMode} step={step} loading={operation?.key==='preview'} layers={layers} setLayers={setLayers} rasterAvailable={rasterAvailable} rasterStatus={rasterStatus} rasterOpacity={rasterOpacity} setRasterOpacity={setRasterOpacity} twilightOpacity={twilightOpacity} setTwilightOpacity={setTwilightOpacity} display={mapDisplay} setDisplay={setMapDisplay} requestedTimeH={requestedTimeH} actualTimeH={actualTimeH} stationCount={stationCount} exportReady={points.length>0 || Boolean(solarGeometry)} onExportError={setMapError} onEnlarge={()=>setMapEnlarged(true)}/>} {p.id==='timeseries' && <TimeSeries selected={selected} setSelected={setSelected} load={loadSeries} loading={operation?.key==='timeseries'} series={series} selectedLine={selectedLine} setSelectedLine={setSelectedLine} onEnlarge={()=>setTimeSeriesEnlarged(true)}/>} {p.id==='spectral' && <Spectral selectedLine={selectedLine} fft={fft} morlet={morlet} compute={computeSpectral} loading={operation?.key==='spectral'} status={spectralStatus} onEnlarge={()=>setSpectralEnlarged(true)}/>} {p.id==='candidates' && <Placeholder text="TID candidate detection placeholder."/>} {p.id==='report' && <Placeholder text="Event report and export placeholder."/>}</WorkflowPanel>)}</aside></main>
    {visibilityEnlarged && <PlotModal title="Satellite visibility" onClose={()=>setVisibilityEnlarged(false)}><VisibilityTable arcs={arcs} choose={chooseArc} selectedArcKey={selectedArcKey} enlarged/></PlotModal>}
    {mapEnlarged && <div className="modalBackdrop"><div className="mapModal"><button className="close" onClick={()=>setMapEnlarged(false)} title="Close enlarged map view.">Close ×</button><PreviewPlot raster={activeRaster} rasterOpacity={rasterOpacity} points={points} stationMarkers={stationMarkers} world={world} solarGeometry={solarGeometry} twilightOpacity={twilightOpacity} layers={layers} selected={selected} onStationClick={toggleStationId} prn={prn} actualTimeH={actualTimeH} viewport={viewport} setViewport={setViewport} display={mapDisplay} enlarged/></div></div>}
    {timeSeriesEnlarged && <PlotModal title="Station time series" onClose={()=>setTimeSeriesEnlarged(false)}><button onClick={()=>exportSvgPng('.modalPlot .series','TID_timeseries.png')}>Export PNG</button><SeriesPlot series={series} selectedLine={selectedLine} setSelectedLine={setSelectedLine} large/></PlotModal>}
    {spectralEnlarged && <PlotModal title="Spectral analysis" onClose={()=>setSpectralEnlarged(false)}><Spectral selectedLine={selectedLine} fft={fft} morlet={morlet} compute={computeSpectral} loading={operation?.key==='spectral'} status={spectralStatus} enlarged/></PlotModal>}
    <footer>References · dTEC is vertical dTEC · IPP height 450 km · GPS PRN prefix G · min elevation 50°</footer>
  </div>;
}
function WorkflowPanel({panel,open,toggle,onEnlarge,children}:any) { const can = ['visibility','map','timeseries','spectral'].includes(panel.id); return <section className="workflow"><div className="workflowTitle"><button onClick={toggle}>{open?'▾':'▸'} {panel.n}. {panel.title}</button><button onClick={onEnlarge} disabled={!can} title={can ? 'Open this panel in a larger overlay.' : 'No enlargement for this panel.'}>Enlarge</button></div>{open && <div className="workflowBody">{children}</div>}</section>; }
function Summary({manifest}:{manifest:Manifest|null}) { if(!manifest) return <p className="placeholder">Import a folder to view metadata.</p>; return <div className="summary"><p><b>Stations:</b> {manifest.station_count}</p><p><b>GPS PRNs:</b> {manifest.gps_prns.join(', ') || 'None'}</p><p><b>Time range:</b> {manifest.time_range_hours.min}–{manifest.time_range_hours.max} h</p><p><b>Rows:</b> {manifest.valid_rows_after_filters} valid / {manifest.total_rows_seen} seen</p>{(manifest as any).preflight && <pre>{JSON.stringify((manifest as any).preflight, null, 2)}</pre>}<p className="mini">Filters: GPS, elevation ≥{manifest.applied_filters?.min_elevation_deg ?? 50}°, lon -20..50, lat 20..80.</p></div>; }
function visibilityStatus(a:Arc) {
  if(!a.eligible_for_interpolation) return {text:'Ineligible', symbol:'⚠', cls:'statusWarn', title:`Ineligible: ${(a.ineligibility_reasons || []).join('; ') || 'quality thresholds not met'}`};
  const s=(a.interpolation_status||'not_generated').replace('_',' ');
  if(s==='building') return {text:'Building', symbol:'◌', cls:'statusBuild', title:'Building interpolated maps'};
  if(s==='ready') return {text:'Ready', symbol:'✓', cls:'statusOk', title:'Ready'};
  if(s==='partial') return {text:'Partial', symbol:'◐', cls:'statusPartial', title:'Partial map coverage'};
  if(s==='failed') return {text:'Failed', symbol:'×', cls:'statusFail', title:'Failed'};
  return {text:'Not generated', symbol:'○', cls:'statusEmpty', title:'Not generated'};
}
function StatusSymbol({info}:{info:{text:string; symbol:string; cls:string; title:string}}) { return <span className={`statusSymbol ${info.cls}`} title={info.title} aria-label={info.text}>{info.symbol}</span>; }
function VisibilityTable({arcs,choose,selectedArcKey,enlarged=false}:any) {
  const [sort,setSort]=useState('prn');
  const sorted=[...arcs].sort((a:Arc,b:Arc)=> sort==='start'?a.start_time_h-b.start_time_h:sort==='stations'?b.station_count-a.station_count:sort==='duration'?b.duration_min-a.duration_min:sort==='status'?visibilityStatus(a).text.localeCompare(visibilityStatus(b).text):`${a.prn}-${a.arc_index}`.localeCompare(`${b.prn}-${b.arc_index}`));
  const heads=enlarged?['PRN','Arc','Start time','End time','Duration min','Rows','Stations','Epochs','Generated maps','Status','Reasons']:['PRN','Arc','Start','End','Min','Sta','Ep','Maps','State'];
  return <div className={enlarged?'visibilityModalTable':'visibilityTableWrap'}>{enlarged && <div className="buttonRow sortControls"><span>Sort by</span>{[['prn','PRN'],['start','start'],['stations','stations'],['duration','duration'],['status','status']].map(([k,l])=><button key={k} onClick={()=>setSort(k)} aria-pressed={sort===k}>{l}</button>)}</div>}<table className={enlarged?'visibilityTable visibilityTableFull':'visibilityTable'}><thead><tr>{heads.map(h=><th key={h}>{h}</th>)}</tr></thead><tbody>{sorted.map((a:Arc)=>{ const info=visibilityStatus(a); const reasons=(a.ineligibility_reasons || []).join('; '); const key=`${a.prn}-${a.arc_index}`; return <tr key={key} className={`${a.eligible_for_interpolation ? '' : 'ineligibleArc'} ${selectedArcKey===key?'selectedArc':''}`} title={reasons || `${a.raw_epoch_count ?? a.epoch_count} raw epochs; ${a.planned_interpolation_count ?? a.usable_epoch_count ?? a.epoch_count} meet the ${a.minimum_epoch_ipp_count ?? 30}-IPP interpolation threshold.`} onClick={()=>choose(a)} tabIndex={0} onKeyDown={(e)=>{ if(e.key==='Enter') choose(a); }}><td>{a.prn}</td><td>{a.arc_index}</td><td>{a.start_time_h.toFixed(enlarged?5:2)}</td><td>{a.end_time_h.toFixed(enlarged?5:2)}</td><td>{a.duration_min.toFixed(1)}</td>{enlarged && <td>{a.row_count}</td>}<td>{a.station_count}</td><td>{a.epoch_count}</td><td>{a.generated_map_count || 0} / {(a.planned_interpolation_count ?? a.usable_epoch_count ?? a.epoch_count)}</td><td className={info.cls}>{enlarged ? info.text : <StatusSymbol info={info}/>}</td>{enlarged && <td className="reasonCell">{reasons || 'Eligible for interpolation'}</td>}</tr>; })}</tbody></table>{!enlarged && <p className="statusLegend"><span><StatusSymbol info={{text:'Eligible/Ready',symbol:'✓',cls:'statusOk',title:'Eligible or ready'}}/> Eligible/Ready</span><span><StatusSymbol info={{text:'Ineligible',symbol:'⚠',cls:'statusWarn',title:'Ineligible'}}/> Ineligible</span><span><StatusSymbol info={{text:'Not generated',symbol:'○',cls:'statusEmpty',title:'Not generated'}}/> Not generated</span><span><StatusSymbol info={{text:'Building',symbol:'◌',cls:'statusBuild',title:'Building'}}/> Building</span><span><StatusSymbol info={{text:'Partial',symbol:'◐',cls:'statusPartial',title:'Partial'}}/> Partial</span><span><StatusSymbol info={{text:'Failed',symbol:'×',cls:'statusFail',title:'Failed'}}/> Failed</span></p>}</div>;
}
function formatDuration(seconds?:number|null) { const s=Math.max(0, Math.floor(seconds || 0)); return `${String(Math.floor(s/3600)).padStart(2,'0')}:${String(Math.floor((s%3600)/60)).padStart(2,'0')}:${String(s%60).padStart(2,'0')}`; }
function finishLocal(iso?:string|null) { return iso ? new Date(iso).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'}) : 'Calculating estimate…'; }
function Visibility({arcs,load,choose,loading,summary,progress,startInterpolation,startArcInterpolation,cancelInterpolation,selectedArcKey,minimumEpochIppCount,setMinimumEpochIppCount,interpolationGridStep,setInterpolationGridStep}:any) {
  const eligible = arcs.filter((a:Arc)=>a.eligible_for_interpolation);
  const plannedMaps = summary?.planned_map_count ?? eligible.reduce((total:number,a:Arc)=>total + (a.epoch_count || 0), 0);
  const running = progress?.state === 'running' || progress?.state === 'cancelling';
  const selectedArc = arcs.find((a:Arc)=>`${a.prn}-${a.arc_index}`===selectedArcKey);
  const canBuildSelected = Boolean(selectedArc && selectedArc.eligible_for_interpolation && (selectedArc.usable_epoch_count ?? selectedArc.epoch_count) > 0 && !running);
  return <div><button onClick={load} disabled={loading} title="Load per-PRN visibility arcs from imported observations.">{loading ? 'Loading visibility…' : 'Load visibility'}</button><details><summary>Advanced</summary><label>Minimum IPPs per interpolated epoch <input type="number" min="3" max="200" value={minimumEpochIppCount} onChange={(e:any)=>setMinimumEpochIppCount(Math.max(3, Math.min(200, Number(e.target.value))))}/></label><label>Interpolation grid resolution <select value={interpolationGridStep} disabled={running} onChange={(e:any)=>setInterpolationGridStep(Number(e.target.value))}><option value={1}>1.0° — fast analysis</option><option value={0.5}>0.5° — detailed refinement</option></select></label><button onClick={()=>startInterpolation(true)}>Rebuild interpolated maps</button></details><p className="mini">Grid: {(summary?.grid_step_deg ?? interpolationGridStep).toFixed(1)}° · {summary?.grid_lat_count ?? (interpolationGridStep === 1 ? 61 : 121)} × {summary?.grid_lon_count ?? (interpolationGridStep === 1 ? 71 : 141)}</p>{running && <p className="mini">{progress.current_prn || 'PRN'} · arc {progress.current_arc_index ?? '—'} · epoch {progress.current_epoch_index ?? '—'}<br/>Generated {progress.generated} · Already cached {progress.already_ready} · Skipped: low station coverage {progress.skipped_low_station_coverage || 0} · Skipped: insufficient geometry {progress.skipped} · Failed {progress.failed}<br/>Elapsed time: {formatDuration(progress.elapsed_seconds)} · Mean per map: {progress.completed_element_count >= 5 && progress.mean_seconds_per_element != null ? `${progress.mean_seconds_per_element.toFixed(2)} s` : 'Calculating estimate…'} · Estimated finish: {progress.completed_element_count >= 5 ? finishLocal(progress.estimated_finish_utc) : 'Calculating estimate…'}</p>}<p className="mini">{loading ? 'Loading visibility…' : `${arcs.length} visibility arcs loaded.`}</p><VisibilityTable arcs={arcs} choose={choose} selectedArcKey={selectedArcKey}/><div className="interpSummary"><p>Eligible arcs: {summary?.eligible_arc_count ?? eligible.length} / {(summary?.eligible_arc_count ?? eligible.length) + (summary?.ineligible_arc_count ?? (arcs.length-eligible.length))}</p><p>Maps planned: {plannedMaps}</p><p>Generated: {summary?.ready_map_count ?? 0}</p><p>Already cached: {progress.already_ready || 0}</p><p>Skipped: low station coverage: {progress.skipped_low_station_coverage || 0}</p><p>Skipped: insufficient geometry: {progress.skipped || 0}</p><p>Missing maps: {summary?.missing_map_count ?? Math.max(0, plannedMaps)}</p><p>Failed maps: {summary?.failed_map_count ?? 0}</p></div><div className="buttonRow"><button onClick={startArcInterpolation} disabled={!canBuildSelected}>Interpolate selected arc</button><button onClick={()=>startInterpolation(false)} disabled={running}>Interpolate all eligible arcs</button><button onClick={cancelInterpolation} disabled={!running}>Cancel interpolation</button></div></div>;
}
function SolarLegendLine({className}:{className:string}) { return <svg className="solarLegendLine" viewBox="0 0 34 10" aria-hidden="true"><line className={className} x1="3" x2="31" y1="5" y2="5"/></svg>; }
function Explorer(p:any) {
  const loadLabel = p.mapMode === 'satellite' ? 'Load satellite track preview' : 'Load epoch map';
  return <div className="summary">
    <label>Mode <select title="Choose whether to draw one epoch, one satellite sample, or a time window." value={p.mapMode} onChange={(e:any)=>p.setMapMode(e.target.value)}><option value="epoch">Current epoch</option><option value="satellite">Whole selected satellite</option><option value="window">Selected time window</option></select></label>
    <label>PRN <select title="Filter map points to a GPS PRN. Selecting a PRN enables automatic current-epoch navigation." value={p.prn} onChange={(e:any)=>p.setPrn(e.target.value)}><option value="">All</option>{p.manifest?.gps_prns.map((x:string)=><option key={x}>{x}</option>)}</select></label>
    {p.mapMode==='epoch' && <><label>Time (h) <input title="Requested epoch in hours from start of day; navigation loads the nearest epoch automatically when a PRN is selected." value={p.timeH} onChange={(e:any)=>p.setTimeH(e.target.value)}/></label><div className="buttonRow">{[-15,-5,-0.5,0.5,5,15].map(m=><button key={m} onClick={()=>p.step(m)} title="Move requested time and automatically load nearest epoch when a PRN is selected.">{m>0?'+':''}{m===-0.5?'- prev epoch':m===0.5?'next epoch':`${m} min`}</button>)}</div></>}
    {p.mapMode==='window' && <><label>Start h <input title="Start time in hours from start of day." value={p.startTimeH} onChange={(e:any)=>p.setStartTimeH(e.target.value)}/></label><label>End h <input title="End time in hours from start of day." value={p.endTimeH} onChange={(e:any)=>p.setEndTimeH(e.target.value)}/></label></>}
    <fieldset className="layers"><legend>Layers</legend>{[['borders','Show country borders','Thin grey country borders below science layers.'],['grid','Show grid','Show longitude/latitude guide lines.'],['ipp','Show IPP points','Show ionospheric pierce points colored by dTEC; clicking selects the station for the current PRN.'],['rays','Show station–IPP rays','Draw fixed station to current IPP lines for the selected epoch.'],['stations','Show station markers','Show subtle station markers; click markers to toggle STATION|PRN selection.'],['stationLabels','Show station labels','Show compact station names near markers; turn off when dense.']].map(([key,label,title])=><label key={key} title={title}><input type="checkbox" checked={p.layers[key]} onChange={(e:any)=>p.setLayers((x:MapLayers)=>({...x,[key]:e.target.checked}))}/>{label}</label>)}<label title="Master toggle for UTC solar terminator, twilight, and ionospheric shell-shadow overlays."><input type="checkbox" checked={p.layers.solar} onChange={(e:any)=>p.setLayers((x:MapLayers)=>({...x,solar:e.target.checked}))}/>Show solar illumination</label>{p.layers.solar && <div className="solarSubLayers">{[['solarHorizon','Horizon 0°'],['solarCivil','Civil twilight -6°'],['solarNautical','Nautical twilight -12°'],['solarAstronomical','Astronomical twilight -18°'],['solarIono','450 km ionospheric shadow'],['solarShade','Shade twilight zones']].map(([key,label])=><label key={key}><input type="checkbox" checked={p.layers[key]} onChange={(e:any)=>p.setLayers((x:MapLayers)=>({...x,[key]:e.target.checked}))}/>{key === 'solarShade' ? null : <SolarLegendLine className={key}/>}<span>{label}</span></label>)}</div>}<label className="mapSlider" title="Global multiplier for neutral-grey twilight and night shading fills only.">Twilight shading opacity <input type="range" min="0" max="100" value={p.twilightOpacity} onChange={(e:any)=>p.setTwilightOpacity(Number(e.target.value))}/><span>{p.twilightOpacity}%</span></label><label title={p.rasterAvailable ? 'Show interpolated dTEC raster.' : 'No ready interpolated grid for this epoch.'}><input type="checkbox" checked={p.layers.dtec && p.rasterAvailable} disabled={!p.rasterAvailable} onChange={(e:any)=>p.setLayers((x:MapLayers)=>({...x,dtec:e.target.checked}))}/>Show interpolated dTEC map</label><label>Interpolated map opacity <input type="range" min="0" max="100" value={p.rasterOpacity} onChange={(e:any)=>p.setRasterOpacity(Number(e.target.value))}/>{p.rasterOpacity}%</label><p className="mini">{p.rasterStatus}</p></fieldset>
    <details title="Advanced map sampling and display settings; ordinary current-epoch navigation does not require these."><summary>Advanced</summary>{p.mapMode==='epoch' && <label>Tolerance seconds <input type="number" value={p.tol} onChange={(e:any)=>p.setTol(Number(e.target.value))}/></label>}<label>Max points <input type="number" value={p.maxPoints} onChange={(e:any)=>p.setMaxPoints(Number(e.target.value))}/></label><MapDisplayControls display={p.display} setDisplay={p.setDisplay}/></details>
    <button onClick={()=>p.loadPreview()} disabled={p.loading} title="Fallback/manual refresh for the map.">{p.loading ? 'Loading map points…' : loadLabel}</button>
    <div className="buttonRow"><button onClick={()=>exportActiveMap(p.prn, p.actualTimeH || p.timeH, p.onExportError)} disabled={!p.exportReady} title="Export the active main SVG map view to a PNG file.">Export PNG</button><button disabled title="Export GIF will be added in a later animation stage.">Export GIF</button><button onClick={p.onEnlarge} title="Open a larger Map Explorer view while preserving PRN, time, and layer state.">Enlarge</button></div>
    <div className="mapStats"><p><b>Requested time:</b> {p.requestedTimeH || 'n/a'}</p><p><b>Actual epoch time:</b> {p.actualTimeH || 'n/a'}</p><p><b>IPP points:</b> {p.count}</p><p><b>Stations:</b> {p.stationCatalog ? `${p.stationCatalog.resolved} / ${p.stationCatalog.total} resolved` : p.stationCount}</p></div>
    {p.mapMode==='satellite' && <p className="mini">Whole satellite mode displays a deterministic sample, not all points.</p>}{p.limitReached && <p className="mini">Deterministic sample limit reached.</p>}
  </div>;
}
function MapDisplayControls({display,setDisplay}:any) {
  const slider=(key:keyof MapDisplaySettings,label:string,min:number,max:number,step:number,suffix='px')=><label className="mapSlider">{label} <input type="range" min={min} max={max} step={step} value={display[key]} onChange={(e:any)=>setDisplay((d:MapDisplaySettings)=>({...d,[key]:Number(e.target.value)}))}/><span>{display[key]}{suffix}</span></label>;
  return <div className="mapDisplayControls"><p className="mini">Map layer display controls</p>{slider('ippMarkerSize','IPP marker size',2,10,1)}{slider('stationMarkerSize','Station marker size',4,16,1)}{slider('stationLabelSize','Station label size',7,16,1)}{slider('rayWidth','Station–IPP ray width',0.3,3,0.1)}{slider('rayOpacity','Station–IPP ray opacity',0,100,1,'%')}<label>dTEC colour range <select value={display.dtecRange} onChange={(e:any)=>setDisplay((d:MapDisplaySettings)=>({...d,dtecRange:Number(e.target.value)}))}><option value={0.5}>±0.5 TECU — TID contrast</option><option value={1}>±1.0 TECU — default</option><option value={2.5}>±2.5 TECU</option><option value={display.dtecRange}>Custom</option></select></label><label>Custom dTEC range <input type="number" min="0.1" step="0.1" value={display.dtecRange} onChange={(e:any)=>setDisplay((d:MapDisplaySettings)=>({...d,dtecRange:Math.max(0.1,Number(e.target.value))}))}/></label></div>;
}
function TimeSeries({selected,setSelected,load,loading,series,selectedLine,setSelectedLine,onEnlarge}:any) { return <div><p className="selectedChips">{selected.length ? selected.map((s:string)=><button key={s} onClick={()=>setSelected((x:string[])=>x.filter(y=>y!==s))}>{s} ×</button>) : <span className="placeholder">Click map points to select station/PRN.</span>}</p><button onClick={load} disabled={!selected.length || loading} title="Load dTEC time series for selected stations.">{loading ? 'Loading time series…' : 'Load time series'}</button><button onClick={()=>setSelected([])}>Clear</button><button onClick={()=>exportSvgPng('.workflowBody .series','TID_timeseries.png')} disabled={!series.length}>Export PNG</button><button onClick={onEnlarge} disabled={!series.length}>Enlarge</button><SeriesPlot series={series} selectedLine={selectedLine} setSelectedLine={setSelectedLine}/></div>; }
function Spectral({selectedLine,fft,morlet,compute,loading,status,enlarged}:any) { if(!selectedLine) return <p className="placeholder">Select a station time-series line.</p>; return <div><p><b>Selected:</b> {selectedLine}</p><div className="buttonRow"><button onClick={()=>compute('fft')} disabled={loading}>Compute FFT</button><button onClick={()=>compute('morlet')} disabled={loading}>Compute Morlet</button><button onClick={()=>exportSvgPng(`${enlarged?'.modalPlot ':''}.fftPlot`,'TID_fft.png')} disabled={!fft}>Export FFT PNG</button><button onClick={()=>exportSvgPng(`${enlarged?'.modalPlot ':''}.morletPlot`,'TID_morlet.png')} disabled={!morlet}>Export Morlet PNG</button></div><p className="mini">{loading ? 'Working…' : status}</p>{fft && <FftPlot data={fft}/>} {morlet && <MorletPlot data={morlet}/>}</div>; }
function Placeholder({text}:{text:string}) { return <p className="placeholder">{text}<br/><button disabled>Compute FFT</button> <button disabled>Compute Morlet</button></p>; }
function dtecRgb(v:number, range=1):[number,number,number] { const scaled=Math.max(-1,Math.min(1,(Number.isFinite(v)?v:0)/Math.max(1e-9,range))); const stops:[number,[number,number,number]][]=[[-1,[0,45,160]],[-0.5,[30,115,220]],[0,[255,255,255]],[0.5,[220,60,60]],[1,[160,0,20]]]; for(let i=0;i<stops.length-1;i++){ const [a,ca]=stops[i], [b,cb]=stops[i+1]; if(scaled>=a && scaled<=b){ const t=(scaled-a)/(b-a); return [0,1,2].map(k=>Math.round(ca[k]+(cb[k]-ca[k])*t)) as [number,number,number]; }} return scaled<0?stops[0][1]:stops[stops.length-1][1]; }
function dtecColor(v:number, range=1) { const c=dtecRgb(v, range); return `rgb(${c[0]},${c[1]},${c[2]})`; }


function geoToScreen(lon:number, lat:number, viewport:Viewport, plotRect:{x:number;y:number;width:number;height:number}) { return { x: plotRect.x + (lon - viewport.lon_min) / (viewport.lon_max - viewport.lon_min) * plotRect.width, y: plotRect.y + (viewport.lat_max - lat) / (viewport.lat_max - viewport.lat_min) * plotRect.height }; }
function screenToGeo(x:number, y:number, viewport:Viewport, plotRect:{x:number;y:number;width:number;height:number}) { return { lon: viewport.lon_min + (x - plotRect.x) / plotRect.width * (viewport.lon_max - viewport.lon_min), lat: viewport.lat_max - (y - plotRect.y) / plotRect.height * (viewport.lat_max - viewport.lat_min) }; }
function rasterGeoExtent(raster:RasterGrid) { const lons = raster.lon_values || [], lats = raster.lat_values || []; if(!lons.length || !lats.length) return null; return { lon_min: Math.min(...lons), lon_max: Math.max(...lons), lat_min: Math.min(...lats), lat_max: Math.max(...lats) }; }
function rasterImagePlacement(raster:RasterGrid, viewport:Viewport, plotRect:{x:number;y:number;width:number;height:number}) { const extent = rasterGeoExtent(raster); if(!extent) return null; const nw = geoToScreen(extent.lon_min, extent.lat_max, viewport, plotRect); const se = geoToScreen(extent.lon_max, extent.lat_min, viewport, plotRect); return { x: nw.x, y: nw.y, width: se.x - nw.x, height: se.y - nw.y, extent }; }
function rasterViewport(raster:RasterGrid | null) { const extent = raster ? rasterGeoExtent(raster) : null; return extent ? { lon_min: extent.lon_min, lon_max: extent.lon_max, lat_min: extent.lat_min, lat_max: extent.lat_max } : EUROPE_VIEWPORT; }

function rasterToImage(r:RasterGrid, dtecRange=1) {
  const lonN=r.lon_values.length, latN=r.lat_values.length; const canvas=document.createElement('canvas'); canvas.width=lonN; canvas.height=latN; const ctx=canvas.getContext('2d'); if(!ctx) return ''; const img=ctx.createImageData(lonN, latN);
  for(let y=0;y<latN;y++){ const srcY = r.lat_values[0] > r.lat_values[latN-1] ? y : latN-1-y; for(let x=0;x<lonN;x++){ const v=Number(r.values[srcY]?.[x]); const ok=Boolean(r.valid_mask[srcY]?.[x]) && Number.isFinite(v); const i=(y*lonN+x)*4; if(!ok){ img.data[i+3]=0; continue; } const c=dtecRgb(v, dtecRange); img.data[i]=c[0]; img.data[i+1]=c[1]; img.data[i+2]=c[2]; img.data[i+3]=255; }}
  ctx.putImageData(img,0,0); return canvas.toDataURL('image/png');
}

function exportSvgPng(selector:string, filename:string) { const svg=document.querySelector(selector) as SVGSVGElement|null; if(!svg) return; const clone=svg.cloneNode(true) as SVGSVGElement; clone.setAttribute('xmlns','http://www.w3.org/2000/svg'); const box=svg.viewBox.baseVal; const width=box?.width || 900, height=box?.height || 520; const blob=new Blob([new XMLSerializer().serializeToString(clone)],{type:'image/svg+xml;charset=utf-8'}); const url=URL.createObjectURL(blob); const img=new Image(); img.onload=()=>{const canvas=document.createElement('canvas'); canvas.width=width; canvas.height=height; const ctx=canvas.getContext('2d'); if(!ctx) return; ctx.fillStyle='#fff'; ctx.fillRect(0,0,width,height); ctx.drawImage(img,0,0,width,height); URL.revokeObjectURL(url); const a=document.createElement('a'); a.download=filename; a.href=canvas.toDataURL('image/png'); a.click();}; img.src=url; }
function PlotModal({title,onClose,children}:any){ return <div className="modalBackdrop"><div className="mapModal modalPlot"><button className="close" onClick={onClose}>Close ×</button><h2>{title}</h2>{children}</div></div>; }
function exportActiveMap(prn:string, timeH:string, onError:(message:string)=>void) {
  const svg = document.querySelector('.canvas .plot') as SVGSVGElement | null;
  if (!svg) { onError('Export PNG failed: no active map is loaded.'); return; }
  const clone = svg.cloneNode(true) as SVGSVGElement;
  clone.setAttribute('xmlns', 'http://www.w3.org/2000/svg');
  const caption = document.createElementNS('http://www.w3.org/2000/svg', 'text');
  caption.setAttribute('x', '55'); caption.setAttribute('y', '28'); caption.setAttribute('class', 'exportCaption');
  caption.textContent = `TID map ${prn || 'All PRNs'} ${timeH ? `${timeH} h` : ''}`;
  clone.prepend(caption);
  const xml = new XMLSerializer().serializeToString(clone);
  const blob = new Blob([xml], {type:'image/svg+xml;charset=utf-8'});
  const url = URL.createObjectURL(blob);
  const img = new Image();
  img.onload = () => { const box=svg.viewBox.baseVal; const canvas = document.createElement('canvas'); canvas.width = box?.width || 900; canvas.height = box?.height || 560; const ctx = canvas.getContext('2d'); if (!ctx) { onError('Export PNG failed: canvas is unavailable.'); return; } ctx.fillStyle = '#fff'; ctx.fillRect(0,0,canvas.width,canvas.height); ctx.drawImage(img,0,0,canvas.width,canvas.height); URL.revokeObjectURL(url); const a = document.createElement('a'); const safeTime = (timeH || 'unknown').replace(/[^0-9.]+/g, '_'); a.download = `TID_map_${prn || 'ALL'}_${safeTime}h.png`; a.href = canvas.toDataURL('image/png'); a.click(); onError(''); };
  img.onerror = () => { URL.revokeObjectURL(url); onError('Export PNG failed: the current SVG map could not be rasterized.'); };
  img.src = url;
}
function clampViewport(v:Viewport):Viewport { const minSpanLon=2, minSpanLat=2; let lonSpan=Math.max(minSpanLon, Math.min(360, v.lon_max-v.lon_min)); let latSpan=Math.max(minSpanLat, Math.min(170, v.lat_max-v.lat_min)); let lonMin=v.lon_min, latMin=v.lat_min; if(lonMin<NAV_LIMITS.lon_min) lonMin=NAV_LIMITS.lon_min; if(lonMin+lonSpan>NAV_LIMITS.lon_max) lonMin=NAV_LIMITS.lon_max-lonSpan; if(latMin<NAV_LIMITS.lat_min) latMin=NAV_LIMITS.lat_min; if(latMin+latSpan>NAV_LIMITS.lat_max) latMin=NAV_LIMITS.lat_max-latSpan; return {lon_min:lonMin, lon_max:lonMin+lonSpan, lat_min:latMin, lat_max:latMin+latSpan}; }
function zoomViewport(v:Viewport, lon:number, lat:number, factor:number):Viewport { const nextLon=(v.lon_max-v.lon_min)*factor, nextLat=(v.lat_max-v.lat_min)*factor; const fx=(lon-v.lon_min)/(v.lon_max-v.lon_min), fy=(lat-v.lat_min)/(v.lat_max-v.lat_min); return clampViewport({lon_min:lon-fx*nextLon, lon_max:lon+(1-fx)*nextLon, lat_min:lat-fy*nextLat, lat_max:lat+(1-fy)*nextLat}); }
function panViewport(v:Viewport, dLon:number, dLat:number):Viewport { return clampViewport({lon_min:v.lon_min+dLon, lon_max:v.lon_max+dLon, lat_min:v.lat_min+dLat, lat_max:v.lat_max+dLat}); }
function mapGridValues(min:number,max:number){ const out:number[]=[]; for(let v=Math.ceil(min/10)*10; v<=Math.floor(max/10)*10; v+=10) out.push(v); return out; }
function fourPointStarPath(cx:number, cy:number, r:number) { const inner=Math.max(1.5, r*0.42); return `M${cx},${cy-r}L${cx+inner},${cy-inner}L${cx+r},${cy}L${cx+inner},${cy+inner}L${cx},${cy+r}L${cx-inner},${cy+inner}L${cx-r},${cy}L${cx-inner},${cy-inner}Z`; }
function PreviewPlot({raster,rasterOpacity,points,stationMarkers,world,solarGeometry,twilightOpacity=DEFAULT_TWILIGHT_OPACITY,layers,selected,onStationClick,prn,actualTimeH,viewport,setViewport,enlarged,display=DEFAULT_MAP_DISPLAY}:any) { const [tip,setTip]=useState(''); const drag=useRef<any>(null); const v:Viewport=viewport || EUROPE_VIEWPORT; const stationByCode = new Map<string, StationMarker>(stationMarkers.map((m:StationMarker)=>[m.station, m])); const visiblePoints = points; const visibleStations = stationMarkers; const w=900,h=560,padL=55,padT=55,padB=55,plotW=690,plotH=h-padT-padB,cbX=790,clipId=`geoClip-${enlarged?'large':'main'}`; const plotRect={x:padL,y:padT,width:plotW,height:plotH}; const x=(lon:number)=>geoToScreen(lon,0,v,plotRect).x; const y=(lat:number)=>geoToScreen(0,lat,v,plotRect).y; const rasterPlacement = raster?.image_href ? rasterImagePlacement(raster, v, plotRect) : null; const geo=(e:any)=>{ const r=e.currentTarget.getBoundingClientRect(); const sx=(e.clientX-r.left)/r.width*w, sy=(e.clientY-r.top)/r.height*h; return screenToGeo(sx, sy, v, plotRect); }; const zoom=(factor:number, lon=(v.lon_min+v.lon_max)/2, lat=(v.lat_min+v.lat_max)/2)=>setViewport?.((old:Viewport)=>zoomViewport(old,lon,lat,factor)); return <><div className="mapToolbar"><button onClick={()=>zoom(0.8)}>Zoom in</button><button onClick={()=>zoom(1.25)}>Zoom out</button><button onClick={()=>setViewport?.(rasterViewport(raster))}>Reset view</button><span>{v.lon_min.toFixed(1)}..{v.lon_max.toFixed(1)}° lon · {v.lat_min.toFixed(1)}..{v.lat_max.toFixed(1)}° lat</span></div><svg viewBox={`0 0 ${w} ${h}`} className={`plot ${enlarged?'plotLarge':''}`} data-lon-min={v.lon_min} data-lon-max={v.lon_max} data-lat-min={v.lat_min} data-lat-max={v.lat_max} onWheel={(e:any)=>{e.preventDefault(); const g=geo(e); zoom(e.deltaY<0?0.8:1.25,g.lon,g.lat);}} onDoubleClick={()=>setViewport?.(rasterViewport(raster))} onMouseDown={(e:any)=>{ if(e.button===0){ drag.current={x:e.clientX,y:e.clientY,v}; } }} onMouseMove={(e:any)=>{ if(!drag.current) return; const r=e.currentTarget.getBoundingClientRect(); const dx=(e.clientX-drag.current.x)/r.width*w, dy=(e.clientY-drag.current.y)/r.height*h; setViewport?.(panViewport(drag.current.v, -dx/plotW*(drag.current.v.lon_max-drag.current.v.lon_min), dy/plotH*(drag.current.v.lat_max-drag.current.v.lat_min))); }} onMouseUp={()=>drag.current=null} onMouseLeave={()=>drag.current=null}><defs><clipPath id={clipId}><rect x={padL} y={padT} width={plotW} height={plotH}/></clipPath></defs><rect x="0" y="0" width={w} height={h} fill="#fff"/><text x="55" y="28" className="mapTitle">{`PRN ${prn || 'All'}${actualTimeH ? ` · epoch ${actualTimeH} h` : ''}${solarGeometry?.utc_datetime ? ` · ${solarGeometry.utc_datetime}` : ''}`}</text><g className="geographicLayers" clipPath={`url(#${clipId})`}>{layers.solar && layers.solarShade && solarGeometry && <SolarShading solar={solarGeometry} layers={layers} viewport={v} plotRect={plotRect} opacity={twilightOpacity}/>} {layers.dtec && raster?.image_href && rasterPlacement && <image className="dtecRaster" href={raster.image_href} x={rasterPlacement.x} y={rasterPlacement.y} width={rasterPlacement.width} height={rasterPlacement.height} opacity={rasterOpacity/100} preserveAspectRatio="none"><title>{`Natural-neighbour grid ready: ${raster.prn}, ${Number(raster.actual_time_h).toFixed(5)} h, ${raster.station_count} stations, ${raster.grid_step_deg ?? '?'}° grid`}</title></image>}{layers.borders && <Borders world={world} x={x} y={y} viewport={v}/>} {layers.grid && <g className="grid internalGrid">{mapGridValues(v.lon_min,v.lon_max).map(l=><line key={'x'+l} x1={x(l)} x2={x(l)} y1={padT} y2={padT+plotH}/>)}{mapGridValues(v.lat_min,v.lat_max).map(l=><line key={'y'+l} x1={padL} x2={padL+plotW} y1={y(l)} y2={y(l)}/>)}</g>}{layers.solar && solarGeometry && <SolarContours solar={solarGeometry} layers={layers} x={x} y={y} viewport={v}/>} {layers.rays && <g className="stationRays" style={{'--ray-width':display.rayWidth,'--ray-opacity':display.rayOpacity/100} as any}>{visiblePoints.map((p:Point,i:number)=>{ const m=stationByCode.get(p.station); if(!m) return null; return <line key={`ray-${i}`} x1={x(m.lon)} y1={y(m.lat)} x2={x(p.ipp_lon)} y2={y(p.ipp_lat)}/>;})}</g>} {layers.ipp && <g className="ippMarkers">{visiblePoints.map((p:Point,i:number)=><circle key={i} cx={x(p.ipp_lon)} cy={y(p.ipp_lat)} r={display.ippMarkerSize} fill={dtecColor(p.dtec, display.dtecRange)} stroke="#44515f" onMouseEnter={()=>setTip(`IPP ${p.station}|${p.prn}; dTEC=${p.dtec} TECU time=${p.time_h} h elev=${p.elevation}; lon=${p.ipp_lon.toFixed(4)} lat=${p.ipp_lat.toFixed(4)}`)}><title>{`IPP for station ${p.station}; PRN ${p.prn}; dTEC=${p.dtec} TECU; time=${p.time_h} h; elevation=${p.elevation}; IPP lon=${p.ipp_lon}, lat=${p.ipp_lat}`}</title></circle>)}</g>}{layers.stations && <g className="stationMarkers">{visibleStations.map((m:StationMarker)=>{ const ids = selected.filter((id:string)=>id.startsWith(`${m.station}|`)); const sel = ids.length > 0; const sx=x(m.lon), sy=y(m.lat); return <g key={m.station} className={`stationMarker ${sel?'selectedStation':''}`} onMouseEnter={()=>setTip(`${m.station} — ${m.city || 'Unknown city'}, ${m.country || 'unknown'}; ${m.lat.toFixed(4)}, ${m.lon.toFixed(4)}; ${m.full_site_id || 'no identifier'}`)}><title>{`${m.station} — ${m.city || 'Unknown city'}, ${m.country || 'unknown'}; lat ${m.lat.toFixed(4)}, lon ${m.lon.toFixed(4)}; id ${m.full_site_id || 'n/a'}.`}</title>{sel && <circle cx={sx} cy={sy} r={display.stationMarkerSize+3} className="stationHalo"/>}<path className="stationStar" d={fourPointStarPath(sx,sy,display.stationMarkerSize/2)}/>{layers.stationLabels && <text className="stationLabel" x={sx+display.stationMarkerSize*.7} y={sy-display.stationMarkerSize*.35} style={{fontSize:display.stationLabelSize}}>{m.station}</text>}<circle cx={sx} cy={sy} r={Math.max(8, display.stationMarkerSize)} className="stationHitTarget" onClick={()=>onStationClick(m.station, prn)}/></g>;})}</g>}</g><g className="ticks">{mapGridValues(v.lon_min,v.lon_max).map(l=><g key={'tx'+l}><line x1={x(l)} x2={x(l)} y1={padT+plotH} y2={padT+plotH+5}/><text x={x(l)-10} y={h-18}>{l}°</text></g>)}{mapGridValues(v.lat_min,v.lat_max).map(l=><g key={'ty'+l}><line x1={padL-5} x2={padL} y1={y(l)} y2={y(l)}/><text x={12} y={y(l)+4}>{l}°</text></g>)}</g><rect className="mapFrame" x={padL} y={padT} width={plotW} height={plotH} fill="none" stroke="#526070"/><Colorbar x={cbX} y={padT} height={plotH} range={display.dtecRange}/><metadata>{`viewport lon_min=${v.lon_min} lon_max=${v.lon_max} lat_min=${v.lat_min} lat_max=${v.lat_max}`}</metadata></svg><p className="tooltip">{tip || 'Click station markers to toggle STATION|PRN selection; IPP markers show hover details only.'}</p></>; }

function twilightBand(e:number, layers:MapLayers) { if(e >= 0) return null; if(e >= -6) return layers.solarCivil ? {shade:222, alpha:0.38, name:'civil'} : null; if(e >= -12) return layers.solarNautical ? {shade:174, alpha:0.52, name:'nautical'} : null; if(e >= -18) return layers.solarAstronomical ? {shade:128, alpha:0.68, name:'astronomical'} : null; return layers.solarAstronomical ? {shade:62, alpha:0.84, name:'night'} : null; }
function solarElevationAt(lon:number, lat:number, lons:number[], lats:number[], vals:number[][]) {
  const ix=Math.max(0, Math.min(lons.length-2, upperIndex(lons, lon)-1)); const iy=Math.max(0, Math.min(lats.length-2, upperIndex(lats, lat)-1));
  const tx=(lon-lons[ix])/Math.max(1e-9,lons[ix+1]-lons[ix]), ty=(lat-lats[iy])/Math.max(1e-9,lats[iy+1]-lats[iy]);
  const a=vals[iy][ix]*(1-tx)+vals[iy][ix+1]*tx, b=vals[iy+1][ix]*(1-tx)+vals[iy+1][ix+1]*tx; return a*(1-ty)+b*ty;
}
function upperIndex(values:number[], value:number) { let lo=0, hi=values.length-1; while(lo<hi){ const mid=Math.floor((lo+hi)/2); if(values[mid] <= value) lo=mid+1; else hi=mid; } return lo; }
function SolarShading({solar,layers,viewport,plotRect,opacity}:any) {
  const renderKey = `${solar.utc_datetime}|${solar.subsolar_latitude}|${solar.subsolar_longitude}|${viewport.lon_min}|${viewport.lon_max}|${viewport.lat_min}|${viewport.lat_max}|${layers.solarCivil}|${layers.solarNautical}|${layers.solarAstronomical}|${opacity}|${plotRect.width}|${plotRect.height}`;
  const href = useMemo(() => twilightShadingImage(solar, layers, viewport, plotRect.width, plotRect.height, opacity), [renderKey]);
  return href ? <g className="twilightShading" data-render-key={renderKey}><title>Twilight shading image from bilinearly interpolated solar elevation; daylight transparent with neutral-grey twilight/night bands.</title><image className="twilightImage" href={href} x={plotRect.x} y={plotRect.y} width={plotRect.width} height={plotRect.height} preserveAspectRatio="none"/></g> : null;
}
function twilightShadingImage(solar:any, layers:MapLayers, viewport:Viewport, width:number, height:number, opacity:number) {
  if(!layers.solarCivil && !layers.solarNautical && !layers.solarAstronomical) return '';
  const canvas=document.createElement('canvas'); canvas.width=width; canvas.height=height; const ctx=canvas.getContext('2d'); if(!ctx) return '';
  const img=ctx.createImageData(width,height); const lons:number[]=solar.lon_values, lats:number[]=solar.lat_values, vals:number[][]=solar.solar_elevation_deg; const multiplier=Math.max(0, Math.min(100, opacity))/100;
  for(let py=0; py<height; py++) { const lat=viewport.lat_max-(py+0.5)/height*(viewport.lat_max-viewport.lat_min); for(let px=0; px<width; px++) { const lon=viewport.lon_min+(px+0.5)/width*(viewport.lon_max-viewport.lon_min); const band=twilightBand(solarElevationAt(lon,lat,lons,lats,vals), layers); if(!band) continue; const k=(py*width+px)*4; img.data[k]=band.shade; img.data[k+1]=band.shade; img.data[k+2]=band.shade; img.data[k+3]=Math.round(255*band.alpha*multiplier); }}
  ctx.putImageData(img,0,0); return canvas.toDataURL('image/png');
}
function contourSegments(solar:any, threshold:number, x:any, y:any, viewport:Viewport) {
  const segs:string[]=[]; const lons:number[]=solar.lon_values, lats:number[]=solar.lat_values, vals:number[][]=solar.solar_elevation_deg;
  const interp=(a:number,b:number,t:number)=> Math.abs(b-a)<1e-9 ? 0.5 : (t-a)/(b-a);
  for(let iy=0; iy<lats.length-1; iy++) for(let ix=0; ix<lons.length-1; ix++) {
    if(lons[ix+1] < viewport.lon_min || lons[ix] > viewport.lon_max || lats[iy+1] < viewport.lat_min || lats[iy] > viewport.lat_max) continue;
    const v00=vals[iy][ix], v10=vals[iy][ix+1], v11=vals[iy+1][ix+1], v01=vals[iy+1][ix]; const pts:[number,number][]=[];
    if((v00-threshold)*(v10-threshold)<=0 && v00!==v10) pts.push([lons[ix]+interp(v00,v10,threshold)*(lons[ix+1]-lons[ix]), lats[iy]]);
    if((v10-threshold)*(v11-threshold)<=0 && v10!==v11) pts.push([lons[ix+1], lats[iy]+interp(v10,v11,threshold)*(lats[iy+1]-lats[iy])]);
    if((v01-threshold)*(v11-threshold)<=0 && v01!==v11) pts.push([lons[ix]+interp(v01,v11,threshold)*(lons[ix+1]-lons[ix]), lats[iy+1]]);
    if((v00-threshold)*(v01-threshold)<=0 && v00!==v01) pts.push([lons[ix], lats[iy]+interp(v00,v01,threshold)*(lats[iy+1]-lats[iy])]);
    for(let p=0; p+1<pts.length; p+=2) segs.push(`M${x(pts[p][0])},${y(pts[p][1])}L${x(pts[p+1][0])},${y(pts[p+1][1])}`);
  }
  return segs;
}
function SolarContours({solar,layers,x,y,viewport}:any) {
  const enabled = [{key:'solarHorizon', t:0, label:'Horizon 0°'}, {key:'solarCivil', t:-6, label:'Civil twilight -6°'}, {key:'solarNautical', t:-12, label:'Nautical twilight -12°'}, {key:'solarAstronomical', t:-18, label:'Astronomical twilight -18°'}, {key:'solarIono', t:solar.ionospheric_shadow.threshold_deg, label:'450 km ionospheric shadow'}].filter(c=>layers[c.key]);
  return <g className="solarContours"><title>{`Subsolar point ${solar.subsolar_latitude.toFixed(2)}°, ${solar.subsolar_longitude.toFixed(2)}°. Ionospheric shadow threshold ${solar.ionospheric_shadow.formula} = ${solar.ionospheric_shadow.threshold_deg.toFixed(2)}° for R=${solar.ionospheric_shadow.earth_radius_km} km, h=${solar.ionospheric_shadow.shell_height_km} km.`}</title>{enabled.flatMap(c=>contourSegments(solar,c.t,x,y,viewport).map((d,i)=><path key={`${c.key}-${i}`} d={d} className={c.key}><title>{c.label}</title></path>))}</g>;
}

function Colorbar({x,y,height,range}:{x:number;y:number;height:number;range:number}) { const ticks=[-range,-range/2,0,range/2,range]; return <g className="colorbar"><title>dTEC [TECU], display-only selected linear scale.</title><defs><linearGradient id="dtecGradient" x1="0" x2="0" y1="1" y2="0"><stop offset="0%" stopColor={dtecColor(-range, range)}/><stop offset="50%" stopColor={dtecColor(0, range)}/><stop offset="100%" stopColor={dtecColor(range, range)}/></linearGradient></defs><rect x={x} y={y} width="18" height={height} fill="url(#dtecGradient)" stroke="#526070"/><text x={x-22} y={y-12}>dTEC [TECU]</text>{ticks.map(t=><g key={t}><line x1={x+18} x2={x+24} y1={y+(1-(t+range)/(2*range))*height} y2={y+(1-(t+range)/(2*range))*height}/><text x={x+28} y={y+(1-(t+range)/(2*range))*height+4}>{t>0?`+${t}`:t}</text></g>)}</g>; }
function Borders({world,x,y,viewport}:any){
  const paths:string[]=[];
  const inMapBounds=(c:any)=>Array.isArray(c) && c.length >= 2 && c[0] >= viewport.lon_min && c[0] <= viewport.lon_max && c[1] >= viewport.lat_min && c[1] <= viewport.lat_max;
  const addRing=(coords:any[])=>{
    let d='';
    coords.forEach((c:any)=>{
      if(!inMapBounds(c)){ if(d){ paths.push(d); d=''; } return; }
      d += `${d?'L':'M'}${x(c[0])},${y(c[1])}`;
    });
    if(d) paths.push(d);
  };
  const addGeometry=(g:any)=>{
    if(!g) return;
    if(g.type==='LineString') addRing(g.coordinates);
    if(g.type==='Polygon') g.coordinates.forEach(addRing);
    if(g.type==='MultiPolygon') g.coordinates.forEach((polygon:any[])=>polygon.forEach(addRing));
  };
  const addGeoJson=(item:any)=>{
    if(!item) return;
    if(item.type==='FeatureCollection') item.features?.forEach(addGeoJson);
    else if(item.type==='Feature') addGeometry(item.geometry);
    else addGeometry(item);
  };
  addGeoJson(world);
  return paths.length ? <g className="borders">{paths.map((d,i)=><path key={i} d={d}/>)}</g> : null;
}
function axisTicks(min:number,max:number,n=5){ return Array.from({length:n},(_,i)=>min+(max-min)*i/(n-1)); }
function SeriesPlot({series,selectedLine,setSelectedLine,large}:any){ const [tip,setTip]=useState(''); if(!series?.length) return null; const pts=series.flatMap((s:Series)=>s.points); if(!pts.length) return <p className="placeholder">No time-series points.</p>; const w=large?920:360,h=large?520:240,padL=52,padB=42,padT=24,padR=18; const minT=Math.min(...pts.map((p:any)=>p.time_h)), maxT=Math.max(...pts.map((p:any)=>p.time_h)); const minD=-1, maxD=1; const clipped=pts.filter((p:any)=>p.dtec < -1 || p.dtec > 1).length; const x=(t:number)=>padL+(t-minT)/Math.max(1e-9,maxT-minT)*(w-padL-padR); const y=(d:number)=>h-padB-(d-minD)/Math.max(1e-9,maxD-minD)*(h-padT-padB); const colors=['#0077b6','#d97706','#2b9348','#d00000','#6d28d9','#0f766e','#be185d','#475569']; return <><svg viewBox={`0 0 ${w} ${h}`} className={`series ${large?'seriesLarge':''}`}>{axisTicks(minT,maxT).map(t=><g key={'xt'+t}><line x1={x(t)} x2={x(t)} y1={padT} y2={h-padB}/><text x={x(t)-14} y={h-14}>{t.toFixed(2)}</text></g>)}{axisTicks(minD,maxD).map(d=><g key={'yd'+d}><line x1={padL} x2={w-padR} y1={y(d)} y2={y(d)}/><text x={8} y={y(d)+4}>{d.toFixed(2)}</text></g>)}<text x={w/2-36} y={h-4}>Time [h UT]</text><text x={16} y={18}>dTEC [TECU]</text>{series.map((s:Series,i:number)=>{const key=`${s.station}|${s.prn}`; const d=s.points.map((p,j)=>`${j?'L':'M'}${x(p.time_h)},${y(Math.max(-1, Math.min(1, p.dtec)))}`).join(''); return <path key={key} d={d} className={selectedLine===key?'line selectedLine':'line'} style={{stroke:colors[i%colors.length]}} onClick={()=>setSelectedLine(key)} onMouseMove={(e:any)=>{const r=e.currentTarget.ownerSVGElement.getBoundingClientRect(); const time=minT+(e.clientX-r.left)/r.width*(maxT-minT); const near=s.points.reduce((a,b)=>Math.abs(b.time_h-time)<Math.abs(a.time_h-time)?b:a,s.points[0]); setTip(`${s.station} time ${near.time_h.toFixed(4)} h dTEC ${near.dtec.toFixed(3)} TECU`);}}><title>{`${key}; click selects for spectral analysis.`}</title></path>})}<g className="legend">{series.map((s:Series,i:number)=>{const key=`${s.station}|${s.prn}`; return <g key={key} transform={`translate(${padL+i%2*120},${padT+16*Math.floor(i/2)})`} onClick={()=>setSelectedLine(key)}><line x1="0" x2="18" y1="0" y2="0" style={{stroke:colors[i%colors.length],strokeWidth:selectedLine===key?4:2}}/><text x="24" y="4">{s.station}</text></g>})}</g></svg>{clipped > 0 && <p className="mini">{clipped} values outside displayed range [-1, 1] TECU</p>}<p className="tooltip">{tip || 'Hover a line for station, time, and dTEC. Click a line to select it for spectral analysis.'}</p></>; }
function FftPlot({data}:{data:FftResult}){ const [tip,setTip]=useState(''); const w=360,h=250,padL=52,padB=46,padT=28,padR=18; const xs=data.period_min, ys=data.amplitude; const maxY=Math.max(...ys,1e-9); const xMin=Math.min(...xs,2), xMax=Math.max(...xs,180); const x=(v:number)=>padL+(v-xMin)/Math.max(1e-9,xMax-xMin)*(w-padL-padR); const y=(v:number)=>h-padB-v/maxY*(h-padT-padB); const d=xs.map((v,i)=>`${i?'L':'M'}${x(v)},${y(ys[i])}`).join(''); return <><svg viewBox={`0 0 ${w} ${h}`} className="series fftPlot"><text x="112" y="18">FFT amplitude</text>{axisTicks(xMin,xMax,5).map(t=><g key={'fx'+t}><line x1={x(t)} x2={x(t)} y1={padT} y2={h-padB}/><text x={x(t)-12} y={h-14}>{t.toFixed(0)}</text></g>)}{axisTicks(0,maxY,5).map(a=><g key={'fy'+a}><line x1={padL} x2={w-padR} y1={y(a)} y2={y(a)}/><text x="8" y={y(a)+4}>{a.toFixed(2)}</text></g>)}<rect x={padL} y={padT} width={w-padL-padR} height={h-padT-padB} fill="none" stroke="#526070"/><text x="130" y={h-8}>Period [min]</text><text x="4" y="18">Amplitude [TECU]</text><path d={d} className="line selectedLine" style={{stroke:'#2563eb'}} onMouseMove={(e:any)=>{const r=e.currentTarget.ownerSVGElement.getBoundingClientRect(); const period=xMin+(e.clientX-r.left)/r.width*(xMax-xMin); const idx=xs.reduce((best, v, i)=>Math.abs(v-period)<Math.abs(xs[best]-period)?i:best,0); setTip(`Period ${xs[idx].toFixed(2)} min; amplitude ${ys[idx].toFixed(4)} TECU`);}}/></svg><p className="tooltip">{tip || 'Hover FFT line for period and amplitude.'}</p></>; }
function MorletPlot({data}:{data:MorletResult}){ const w=380,h=280,padL=52,padB=46,padT=32,padR=54; const t0=Math.min(...data.time_h), t1=Math.max(...data.time_h); const p0=Math.min(...data.period_min), p1=Math.max(...data.period_min); const flat=data.power.flat(); const max=Math.max(...flat,1e-12); const x=(v:number)=>padL+(v-t0)/Math.max(1e-9,t1-t0)*(w-padL-padR); const y=(v:number)=>h-padB-(v-p0)/(p1-p0)*(h-padT-padB); const color=(v:number)=>`hsl(${240-240*Math.sqrt(v/max)},80%,55%)`; const cbX=w-34, cbY=padT, cbH=h-padT-padB; return <svg viewBox={`0 0 ${w} ${h}`} className="series morletPlot"><text x="78" y="18">Morlet power · {data.station} {data.prn} · {t0.toFixed(2)}–{t1.toFixed(2)} h</text>{axisTicks(t0,t1,5).map(t=><g key={'mt'+t}><line x1={x(t)} x2={x(t)} y1={padT} y2={h-padB}/><text x={x(t)-12} y={h-14}>{t.toFixed(2)}</text></g>)}{axisTicks(p0,p1,5).map(period=><g key={'mp'+period}><line x1={padL} x2={w-padR} y1={y(period)} y2={y(period)}/><text x="8" y={y(period)+4}>{period.toFixed(0)}</text></g>)}{data.period_min.map((period,iy)=>data.time_h.map((time,ix)=>{ const nextT=data.time_h[ix+1]??time+(data.time_h[1]-data.time_h[0]||0.01); const nextP=data.period_min[iy+1]??period+(data.period_min[1]-data.period_min[0]||1); return <rect key={`${ix}-${iy}`} x={x(time)} y={y(nextP)} width={Math.max(1,x(nextT)-x(time)+.5)} height={Math.max(1,y(period)-y(nextP)+.5)} fill={color(data.power[iy]?.[ix]||0)}/>;}))}<rect x={padL} y={padT} width={w-padL-padR} height={h-padT-padB} fill="none" stroke="#526070"/><text x="130" y={h-8}>Time [h UT]</text><text x="4" y="18">Period [min]</text><defs><linearGradient id="powerGradient" x1="0" x2="0" y1="1" y2="0"><stop offset="0%" stopColor={color(0)}/><stop offset="100%" stopColor={color(max)}/></linearGradient></defs><rect x={cbX} y={cbY} width="14" height={cbH} fill="url(#powerGradient)" stroke="#526070"/><text x={cbX-6} y={cbY-10}>Power</text>{axisTicks(0,max,4).map(v=><g key={'cb'+v}><line x1={cbX+14} x2={cbX+19} y1={cbY+(1-v/max)*cbH} y2={cbY+(1-v/max)*cbH}/><text x={cbX+21} y={cbY+(1-v/max)*cbH+4}>{v.toFixed(2)}</text></g>)}</svg>; }

